code = """import json

# Load emergency funding projects
funding_emergency = locals()['var_functions.query_db:40']

# Load civic documents
civic_docs_path = locals()['var_functions.query_db:42']
with open(civic_docs_path) as f:
    civic_docs = json.load(f)

# Initialize results list
results = []

# For each emergency/FEMA project from funding
for project in funding_emergency:
    proj_name = project['Project_Name']
    proj_name_lower = proj_name.lower()
    
    # Default values
    status = 'not started'
    proj_type = 'disaster' if 'fema' in proj_name_lower else 'capital'
    
    # Look for status information in civic documents
    for doc in civic_docs:
        text = doc['text'].lower()
        
        # Check if this project is mentioned
        base_name = proj_name.replace('(FEMA Project)', '').replace('(FEMA/CalOES Project)', '').replace('(CalJPIA/FEMA Project)', '').strip()
        
        if base_name.lower() in text:
            # Check for status
            if 'under construction' in text:
                status = 'completed'
            elif 'design' in text and 'complete design' not in text:
                status = 'design'
            
    # Build result
    results.append({
        'Project_Name': proj_name,
        'Funding_Source': project['Funding_Source'],
        'Amount': int(project['Amount']),
        'Status': status,
        'Type': proj_type
    })

# Print results in simple format
print('__RESULT__:')
output = []
output.append('EMERGENCY/FEMA PROJECTS')
output.append('=' * 50)
output.append('')

for r in results:
    output.append('Project: ' + r['Project_Name'])
    output.append('Funding: ' + r['Funding_Source'] + ' - $' + str(r['Amount']))
    output.append('Status: ' + r['Status'])
    output.append('Type: ' + r['Type'])
    output.append('')

print('\n'.join(output))"""

